ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?date ?concerthall WHERE {
  ?c a :Concert .
  ?t a :Tickets .
  ?t p:hasconcerts ?c .
  ?c p:id ?id_g .
  ?c p:date ?date .
  ?c p:concertHall ?concerthall .
}
GROUP BY ?id_g ?date ?concerthall
LIMIT 3 }
  component_2: { SELECT ?date ?city WHERE {
  ?c a :Concert .
  ?t a :Tickets .
  ?t p:hasconcerts ?c .
  ?c p:id ?id_g .
  ?c p:date ?date .
  ?c p:city ?city .
}
GROUP BY ?id_g ?date ?city
LIMIT 3 }
  full: { SELECT ?date ?city ?concerthall WHERE {
  ?c a :Concert .
  ?t a :Tickets .
  ?t p:hasconcerts ?c .
  ?c p:id ?id_g .
  ?c p:date ?date .
  ?c p:city ?city .
  ?c p:concertHall ?concerthall .
}
GROUP BY ?id_g ?date ?city ?concerthall
LIMIT 3 }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
CHOICE vague {
  full: { SELECT ?date ?city ?hall ?type (SUM(?q) AS ?tot) WHERE { ?t a :Tickets ; p:type ?type ; p:quantity ?q ; p:hasconcerts ?c . ?c a :Concert ; p:date ?date ; p:city ?city ; p:concertHall ?hall } GROUP BY ?c ?date ?city ?hall ?type }
  component: { SELECT ?date ?hall ?type (SUM(?q) AS ?tot) WHERE { ?t a :Tickets ; p:type ?type ; p:quantity ?q ; p:hasconcerts ?c . ?c a :Concert ; p:date ?date ; p:concertHall ?hall } GROUP BY ?c ?date ?hall ?type }
  component_2: { SELECT ?date ?city ?type (SUM(?q) AS ?tot) WHERE { ?t a :Tickets ; p:type ?type ; p:quantity ?q ; p:hasconcerts ?c . ?c a :Concert ; p:date ?date ; p:city ?city } GROUP BY ?c ?date ?city ?type }
}
